            "NSPOSIXErrorDomain Code=22"
        ));
        assert!(!is_apple_container_daemon_stale_error("Invalid argument"));
        // Log-fetching errors with NSPOSIXErrorDomain Code=2 must NOT match
        assert!(!is_apple_container_daemon_stale_error(
