4080:    async fn wait_for_container_running(name: &str) -> Result<()> {
4081:        const MAX_WAIT_ITERS: usize = 20;
4082:        const WAIT_MS: u64 = 100;
4083:
4084:        for attempt in 0..MAX_WAIT_ITERS {
4085:            let output = tokio::process::Command::new("container")
4086:                .args(["inspect", name])
4087:                .output()
4088:                .await;
4089:
4090:            match output {
4091:                Ok(output) if output.status.success() => {
4092:                    let stdout = String::from_utf8_lossy(&output.stdout);
4093:                    match apple_container_status_from_inspect(&stdout) {
4094:                        Some("running") => return Ok(()),
4095:                        Some("stopped") => {
4096:                            return Err(Error::message(format!(
4097:                                "container {name} failed to stay running after startup"
4098:                            )));
4099:                        },
4100:                        _ => {},
4101:                    }
4102:
4103:                    // `container run -d` can return before inspect status flips to
4104:                    // "running". Keep polling briefly before we declare failure.
4105:                    if attempt + 1 < MAX_WAIT_ITERS {
4106:                        tokio::time::sleep(std::time::Duration::from_millis(WAIT_MS)).await;
4107:                        continue;
4108:                    }
4109:
4110:                    return Err(Error::message(format!(
4111:                        "container {name} did not report running state after startup"
4112:                    )));
4113:                },
4114:                Ok(output) => {
4115:                    let stderr = String::from_utf8_lossy(&output.stderr);
4116:                    if attempt + 1 < MAX_WAIT_ITERS {
4117:                        debug!(
4118:                            name,
4119:                            attempt,
4120:                            %stderr,
4121:                            "container inspect failed while waiting for running state, retrying"
4122:                        );
4123:                        tokio::time::sleep(std::time::Duration::from_millis(WAIT_MS)).await;
4124:                        continue;
4125:                    }
4126:                    return Err(Error::message(format!(
4127:                        "container inspect failed for {name} while waiting for running state: {}",
4128:                        stderr.trim()
4129:                    )));
4130:                },
4131:                Err(e) => {
4132:                    if attempt + 1 < MAX_WAIT_ITERS {
4133:                        debug!(
4134:                            name,
4135:                            attempt,
4136:                            error = %e,
4137:                            "container inspect command failed while waiting for running state, retrying"
4138:                        );
4139:                        tokio::time::sleep(std::time::Duration::from_millis(WAIT_MS)).await;
4140:                        continue;
4141:                    }
4142:                    return Err(e.into());
4143:                },
4144:            }
4145:        }
4146:
4147:        Err(Error::message(format!(
4148:            "container {name} did not become running after startup"
4149:        )))
4150:    }
