4246:        let output = tokio::process::Command::new("container")
4247:            .args(&args)
4248:            .output()
4249:            .await
4250:            .map_err(|e| CreateError::Other(format!("failed to run container command: {e}")))?;
4251:
4252:        if output.status.success() {
4253:            return Ok(());
4254:        }
