4275:    /// Capture the last N lines of container logs (stdout + stderr).
4276:    /// Returns `None` if logs cannot be retrieved.
4277:    async fn capture_container_logs(name: &str, max_lines: usize) -> Option<String> {
4278:        let output = tokio::process::Command::new("container")
4279:            .args(["logs", name])
4280:            .output()
4281:            .await
4282:            .ok()?;
4283:
4284:        let stdout = String::from_utf8_lossy(&output.stdout);
4285:        let stderr = String::from_utf8_lossy(&output.stderr);
4286:        let mut combined = String::new();
4287:        if !stdout.trim().is_empty() {
4288:            combined.push_str(&stdout);
4289:        }
4290:        if !stderr.trim().is_empty() {
4291:            if !combined.is_empty() {
4292:                combined.push('\n');
4293:            }
4294:            combined.push_str(&stderr);
4295:        }
4296:        if combined.trim().is_empty() {
4297:            return None;
4298:        }
4299:
4300:        // Keep only the last N lines.
4301:        let lines: Vec<&str> = combined.lines().collect();
4302:        let tail = if lines.len() > max_lines {
4303:            &lines[lines.len() - max_lines..]
4304:        } else {
4305:            &lines
4306:        };
4307:        Some(tail.join("\n"))
4308:    }
