4320:            Ok(output) if output.status.success() => {
4321:                let stdout = String::from_utf8_lossy(&output.stdout);
4322:                let count = stdout.lines().count();
4323:                diagnostics.push(format!("running containers: {count}"));
4324:            },
4325:            _ => diagnostics.push("running containers: unknown (list failed)".to_string()),
4326:        }
4327:
4328:        // Check the state of the target container.
4329:        let state = Self::inspect_container_state(name).await;
4330:        diagnostics.push(format!("container '{name}' state: {state:?}"));
4331:
4332:        // Capture container logs — this is the most useful piece: it shows
4333:        // WHY the entrypoint exited (e.g. missing binary, image issues).
4334:        match Self::capture_container_logs(name, 10).await {
4335:            Some(logs) => diagnostics.push(format!("container logs: {logs}")),
4336:            None => diagnostics.push("container logs: (empty or unavailable)".to_string()),
4337:        }
4338:
4339:        // Check the service health.
4340:        let service_ok = tokio::process::Command::new("container")
4341:            .args(["system", "status"])
4342:            .stdout(std::process::Stdio::null())
4343:            .stderr(std::process::Stdio::null())
4344:            .status()
4345:            .await
4346:            .is_ok_and(|s| s.success());
4347:        diagnostics.push(format!(
4348:            "container service: {}",
4349:            if service_ok {
4350:                "running"
4351:            } else {
4352:                "not running"
4353:            }
4354:        ));
4355:
4356:        diagnostics.join("; ")
4357:    }
