4491:fn apple_container_status_from_inspect(stdout: &str) -> Option<&'static str> {
4492:    let inspect = stdout.trim();
4493:    if inspect.is_empty() || inspect == "[]" {
4494:        return None;
4495:    }
4496:
4497:    if inspect.contains(r#""status":"running""#) {
4498:        return Some("running");
4499:    }
4500:
4501:    if inspect.contains(r#""status":"stopped""#) || inspect.contains(r#""status":"exited""#) {
4502:        return Some("stopped");
4503:    }
4504:
4505:    None
4506:}
