4544:fn is_apple_container_corruption_error(stderr: &str) -> bool {
4545:    let lower = stderr.to_ascii_lowercase();
4546:    is_apple_container_service_error(stderr)
4547:        || is_apple_container_exists_error(stderr)
4548:        || is_apple_container_daemon_stale_error(stderr)
4549:        || lower.contains("failed to bootstrap container")
4550:        || lower.contains("config.json")
4551:        || lower.contains("vm never booted")
4552:}
