4554:/// Wrapper sandbox that can fail over from a primary backend to a fallback backend.
4555:///
4556:/// This is used on macOS to fail over from Apple Container to Docker when the
4557:/// Apple runtime enters a corrupted state (stale metadata, missing config.json,
4558:/// service errors, etc.).
4559:pub struct FailoverSandbox {
4560:    primary: Arc<dyn Sandbox>,
4561:    fallback: Arc<dyn Sandbox>,
4562:    primary_name: &'static str,
4563:    fallback_name: &'static str,
4564:    use_fallback: RwLock<bool>,
4565:}
4566:
4567:impl FailoverSandbox {
4568:    pub fn new(primary: Arc<dyn Sandbox>, fallback: Arc<dyn Sandbox>) -> Self {
4569:        let primary_name = primary.backend_name();
4570:        let fallback_name = fallback.backend_name();
4571:        Self {
4572:            primary,
4573:            fallback,
4574:            primary_name,
4575:            fallback_name,
4576:            use_fallback: RwLock::new(false),
4577:        }
4578:    }
4579:
4580:    async fn fallback_enabled(&self) -> bool {
4581:        *self.use_fallback.read().await
4582:    }
4583:
4584:    async fn switch_to_fallback(&self, error: &Error) {
4585:        let mut use_fallback = self.use_fallback.write().await;
4586:        if !*use_fallback {
4587:            warn!(
4588:                primary = self.primary_name,
4589:                fallback = self.fallback_name,
4590:                %error,
4591:                "sandbox primary backend failed, switching to fallback backend"
4592:            );
4593:            *use_fallback = true;
4594:        }
4595:    }
4596:
4597:    fn should_failover(&self, error: &Error) -> bool {
4598:        let message = format!("{error:#}");
4599:        match self.primary_name {
4600:            "apple-container" => is_apple_container_corruption_error(&message),
4601:            "docker" => is_docker_failover_error(&message),
4602:            "podman" => is_podman_failover_error(&message),
4603:            _ => false,
4604:        }
4605:    }
4606:}
