4608:#[async_trait]
4609:impl Sandbox for FailoverSandbox {
4610:    fn backend_name(&self) -> &'static str {
4611:        self.primary_name
4612:    }
4613:
4614:    async fn ensure_ready(&self, id: &SandboxId, image_override: Option<&str>) -> Result<()> {
4615:        if self.fallback_enabled().await {
4616:            return self.fallback.ensure_ready(id, image_override).await;
4617:        }
4618:
4619:        match self.primary.ensure_ready(id, image_override).await {
4620:            Ok(()) => Ok(()),
4621:            Err(primary_error) => {
4622:                if !self.should_failover(&primary_error) {
4623:                    return Err(primary_error);
4624:                }
4625:
4626:                self.switch_to_fallback(&primary_error).await;
4627:                let primary_message = format!("{primary_error:#}");
4628:                self.fallback
4629:                    .ensure_ready(id, image_override)
4630:                    .await
4631:                    .map_err(|fallback_error| {
4632:                        Error::message(format!(
4633:                            "primary sandbox backend ({}) failed: {}; fallback backend ({}) also failed: {}",
4634:                            self.primary_name,
4635:                            primary_message,
4636:                            self.fallback_name,
4637:                            fallback_error
4638:                        ))
4639:                    })
4640:            },
4641:        }
4642:    }
4643:
4644:    async fn exec(&self, id: &SandboxId, command: &str, opts: &ExecOpts) -> Result<ExecResult> {
4645:        if self.fallback_enabled().await {
4646:            return self.fallback.exec(id, command, opts).await;
4647:        }
4648:
4649:        match self.primary.exec(id, command, opts).await {
4650:            Ok(result) => Ok(result),
4651:            Err(primary_error) => {
4652:                if !self.should_failover(&primary_error) {
4653:                    return Err(primary_error);
4654:                }
4655:
4656:                self.switch_to_fallback(&primary_error).await;
4657:                let primary_message = format!("{primary_error:#}");
4658:                self.fallback
4659:                    .ensure_ready(id, None)
4660:                    .await
4661:                    .map_err(|fallback_error| {
4662:                        Error::message(format!(
4663:                            "primary sandbox backend ({}) failed during exec: {}; fallback backend ({}) failed to initialize: {}",
4664:                            self.primary_name,
4665:                            primary_message,
4666:                            self.fallback_name,
4667:                            fallback_error
4668:                        ))
4669:                    })?;
4670:                self.fallback.exec(id, command, opts).await
4671:            },
4672:        }
4673:    }
4674:
4675:    async fn cleanup(&self, id: &SandboxId) -> Result<()> {
4676:        if self.fallback_enabled().await {
4677:            let result = self.fallback.cleanup(id).await;
4678:            if let Err(error) = self.primary.cleanup(id).await {
4679:                debug!(
4680:                    backend = self.primary_name,
4681:                    %error,
4682:                    "primary sandbox cleanup failed after failover"
4683:                );
4684:            }
4685:            return result;
4686:        }
4687:
4688:        self.primary.cleanup(id).await
4689:    }
4690:
4691:    async fn build_image(
4692:        &self,
4693:        base: &str,
4694:        packages: &[String],
4695:    ) -> Result<Option<BuildImageResult>> {
4696:        if self.fallback_enabled().await {
4697:            return self.fallback.build_image(base, packages).await;
4698:        }
4699:
4700:        match self.primary.build_image(base, packages).await {
4701:            Ok(result) => Ok(result),
4702:            Err(primary_error) => {
4703:                if !self.should_failover(&primary_error) {
4704:                    return Err(primary_error);
4705:                }
4706:
4707:                self.switch_to_fallback(&primary_error).await;
4708:                self.fallback.build_image(base, packages).await
4709:            },
4710:        }
4711:    }
4712:}
