4721:    async fn ensure_ready(&self, id: &SandboxId, image_override: Option<&str>) -> Result<()> {
4722:        let mut name = self.container_name(id).await;
4723:        let requested_image = image_override.unwrap_or_else(|| self.image());
4724:        let image = self.resolve_local_image(requested_image).await?;
4725:        let tz = self.config.timezone.as_deref();
4726:        let home_volume = self.home_persistence_volume(id)?;
4727:
4728:        const MAX_ATTEMPTS: usize = 3;
4729:        let mut daemon_restarted = false;
4730:
4731:        for attempt in 0..MAX_ATTEMPTS {
4732:            let is_last = attempt + 1 >= MAX_ATTEMPTS;
4733:
4734:            // Phase 1: Check existing container and try to reuse it.
4735:            match Self::inspect_container_state(&name).await {
4736:                ContainerState::Running => {
4737:                    info!(name, "apple container already running");
4738:                    match Self::wait_for_container_exec_ready(&name).await {
4739:                        Ok(()) => {
4740:                            unmark_zombie(&name);
4741:                            return Ok(());
4742:                        },
4743:                        Err(error) => {
4744:                            warn!(
4745:                                name,
4746:                                %error,
4747:                                attempt,
4748:                                "apple container running but exec probe failed, removing"
4749:                            );
4750:                            Self::force_remove_and_wait(&name).await;
4751:                        },
4752:                    }
4753:                },
4754:                ContainerState::Stopped => {
4755:                    info!(name, "apple container stopped, restarting");
4756:                    if Self::try_restart_container(&name).await {
4757:                        info!(name, "apple container restarted");
4758:                        match Self::wait_for_container_exec_ready(&name).await {
4759:                            Ok(()) => {
4760:                                unmark_zombie(&name);
4761:                                return Ok(());
4762:                            },
4763:                            Err(error) => {
4764:                                warn!(
4765:                                    name,
4766:                                    %error,
4767:                                    attempt,
4768:                                    "restarted container failed exec probe, removing"
4769:                                );
4770:                                Self::force_remove_and_wait(&name).await;
4771:                            },
4772:                        }
4773:                    } else {
4774:                        warn!(name, attempt, "container restart failed, removing");
4775:                        Self::force_remove_and_wait(&name).await;
4776:                    }
4777:                },
4778:                ContainerState::NotFound => {
4779:                    debug!(name, "apple container not found, will create");
4780:                },
4781:                ContainerState::Unknown => {
4782:                    info!(name, attempt, "apple container in unknown state, removing");
4783:                    Self::force_remove_and_wait(&name).await;
4784:                },
4785:            }
4786:
4787:            // Phase 2: Create a new container.
4788:            info!(name, image = %image, attempt, "creating apple container");
4789:            match Self::run_container(&name, &image, tz, home_volume.as_deref()).await {
4790:                Ok(()) => {},
4791:                Err(CreateError::AlreadyExists) => {
4792:                    warn!(
4793:                        name,
4794:                        attempt,
4795:                        "container already exists during create, removing and rotating name"
4796:                    );
4797:                    Self::force_remove_and_wait(&name).await;
4798:                    name = self.bump_container_generation(id).await;
4799:                    continue;
4800:                },
4801:                Err(CreateError::ServiceDown) => {
4802:                    return Err(Error::message(
4803:                        "apple container service is not running. \
4804:                         Start it with `container system start` and restart moltis",
4805:                    ));
4806:                },
4807:                Err(CreateError::Other(stderr)) => {
4808:                    // Daemon-stale errors mean the VM subsystem is broken.
4809:                    // Restart the daemon once and retry; bail if already tried.
4810:                    if is_apple_container_daemon_stale_error(&stderr) {
4811:                        Self::force_remove_and_wait(&name).await;
4812:                        if !daemon_restarted && restart_apple_container_service() {
4813:                            daemon_restarted = true;
4814:                            // Let the daemon fully initialize before retrying.
4815:                            tokio::time::sleep(std::time::Duration::from_secs(2)).await;
4816:                            continue;
4817:                        }
4818:                        return Err(Error::message(format!(
4819:                            "apple container daemon has stale Virtualization.framework state \
4820:                             and automatic restart failed (create error: {stderr}). \
4821:                             Restart manually with `container system stop && container system start`"
4822:                        )));
4823:                    }
4824:                    if is_last {
4825:                        let diag = Self::diagnose_container_failure(&name).await;
4826:                        return Err(Error::message(format!(
4827:                            "container run failed for {name} (image={image}): {stderr}; diagnostics: {diag}"
4828:                        )));
