4838:                },
4839:            }
4840:
4841:            // Phase 3: Wait for exec readiness (do NOT rotate name on failure).
4842:            match Self::wait_for_container_exec_ready(&name).await {
4843:                Ok(()) => {
4844:                    info!(name, image = %image, "apple container created and running");
4845:                    unmark_zombie(&name);
4846:
4847:                    // Skip provisioning for pre-built sandbox images.
