4885:                                },
4886:                                Err(restart_error) => {
4887:                                    warn!(
4888:                                        name,
4889:                                        %restart_error,
4890:                                        attempt,
4891:                                        "apple container restart after readiness failure did not recover"
4892:                                    );
4893:                                },
4894:                            }
4895:                        } else {
4896:                            warn!(
4897:                                name,
4898:                                attempt,
4899:                                "apple container restart after readiness failure was unsuccessful"
4900:                            );
