4902:                    }
4903:
4904:                    // Capture logs before removing — this tells us WHY the
4905:                    // entrypoint exited (missing binary, image issue, etc.).
4906:                    let logs = Self::capture_container_logs(&name, 5).await;
4907:
4908:                    // Daemon-stale errors (NSPOSIXErrorDomain EINVAL) mean
4909:                    // the VM subsystem is broken. Restart the daemon once and
4910:                    // retry; bail if we already restarted and it still fails.
4911:                    if let Some(ref log_text) = logs
4912:                        && is_apple_container_daemon_stale_error(log_text)
4913:                    {
4914:                        Self::force_remove_and_wait(&name).await;
4915:                        if !daemon_restarted && restart_apple_container_service() {
4916:                            daemon_restarted = true;
4917:                            // Let the daemon fully initialize before retrying.
4918:                            tokio::time::sleep(std::time::Duration::from_secs(2)).await;
4919:                            continue;
4920:                        }
4921:                        return Err(Error::message(format!(
4922:                            "apple container daemon has stale Virtualization.framework state \
