4985:    async fn exec(&self, id: &SandboxId, command: &str, opts: &ExecOpts) -> Result<ExecResult> {
4986:        let name = self.container_name(id).await;
4987:        info!(name, command, "apple container exec");
4988:
4989:        // Apple Container CLI doesn't support -e flags, so prepend export
4990:        // statements to inject env vars into the shell.
4991:        let mut prefix = String::new();
4992:
4993:        // Inject proxy env vars so traffic routes through the trusted-network
4994:        // proxy running on the host.
4995:        if self.config.network == NetworkPolicy::Trusted {
4996:            let gateway = self.detect_host_gateway(&name).await;
4997:            let proxy_url = format!(
4998:                "http://{}:{}",
4999:                gateway,
5000:                moltis_network_filter::DEFAULT_PROXY_PORT
5001:            );
5002:            let escaped_proxy = proxy_url.replace('\'', "'\\''");
5003:            for key in ["HTTP_PROXY", "http_proxy", "HTTPS_PROXY", "https_proxy"] {
5004:                prefix.push_str(&format!("export {key}='{escaped_proxy}'; "));
5005:            }
5006:            let no_proxy = "localhost,127.0.0.1,::1";
5007:            for key in ["NO_PROXY", "no_proxy"] {
5008:                prefix.push_str(&format!("export {key}='{no_proxy}'; "));
5009:            }
5010:        }
5011:
5012:        for (k, v) in &opts.env {
5013:            // Shell-escape the value with single quotes.
5014:            let escaped = v.replace('\'', "'\\''");
5015:            prefix.push_str(&format!("export {k}='{escaped}'; "));
5016:        }
5017:
5018:        let full_command = if let Some(ref dir) = opts.working_dir {
5019:            format!("{prefix}cd {} && {command}", dir.display())
5020:        } else {
5021:            format!("{prefix}{command}")
5022:        };
5023:
5024:        let args = apple_container_exec_args(&name, full_command);
5025:
5026:        let child = tokio::process::Command::new("container")
5027:            .args(&args)
5028:            .stdout(std::process::Stdio::piped())
5029:            .stderr(std::process::Stdio::piped())
5030:            .stdin(std::process::Stdio::null())
5031:            .spawn()?;
5032:
5033:        let result = tokio::time::timeout(opts.timeout, child.wait_with_output()).await;
5034:
5035:        match result {
5036:            Ok(Ok(output)) => {
5037:                let exit_code = output.status.code().unwrap_or(-1);
5038:                let mut stdout = String::from_utf8_lossy(&output.stdout).into_owned();
5039:                let mut stderr = String::from_utf8_lossy(&output.stderr).into_owned();
5040:
5041:                truncate_output_for_display(&mut stdout, opts.max_output_bytes);
5042:                truncate_output_for_display(&mut stderr, opts.max_output_bytes);
5043:
5044:                debug!(
5045:                    name,
5046:                    exit_code,
5047:                    stdout_len = stdout.len(),
5048:                    stderr_len = stderr.len(),
5049:                    "apple container exec complete"
5050:                );
5051:                Ok(ExecResult {
5052:                    stdout,
5053:                    stderr,
5054:                    exit_code,
5055:                })
5056:            },
5057:            Ok(Err(e)) => {
5058:                warn!(name, %e, "apple container exec spawn failed");
5059:                return Err(Error::message(format!(
5060:                    "container exec failed for {name}: {e}"
5061:                )));
5062:            },
5063:            Err(_) => {
5064:                warn!(
5065:                    name,
5066:                    timeout_secs = opts.timeout.as_secs(),
5067:                    "apple container exec timed out"
5068:                );
5069:                return Err(Error::message(format!(
5070:                    "container exec timed out for {name} after {}s",
5071:                    opts.timeout.as_secs()
5072:                )));
5073:            },
5074:        }
5075:    }
