5109:            .arg(&dockerfile_path)
5110:            .arg(&tmp_dir)
5111:            .stdout(std::process::Stdio::piped())
5112:            .stderr(std::process::Stdio::piped())
5113:            .output()
5114:            .await;
5115:
5116:        let _ = std::fs::remove_dir_all(&tmp_dir);
5117:
5118:        let output = output?;
5119:        if !output.status.success() {
5120:            let stderr = String::from_utf8_lossy(&output.stderr);
5121:            if stderr.contains("XPC connection error") || stderr.contains("Connection invalid") {
5122:                return Err(Error::message(
5123:                    "apple container service is not running. \
5124:                     Start it with `container system start` and restart moltis",
5125:                ));
5126:            }
5127:            return Err(Error::message(format!(
5128:                "container build failed for {tag}: {}",
5129:                stderr.trim()
5130:            )));
5131:        }
5132:
5133:        info!(tag, "pre-built sandbox image ready (apple container)");
5134:        Ok(Some(BuildImageResult { tag, built: true }))
5135:    }
5136:
5137:    async fn cleanup(&self, id: &SandboxId) -> Result<()> {
5138:        let base = self.base_container_name(id);
5139:        let max_generation = self
5140:            .name_generations
5141:            .read()
5142:            .await
5143:            .get(&id.key)
5144:            .copied()
5145:            .unwrap_or(0);
5146:
5147:        for generation in 0..=max_generation {
5148:            let name = if generation == 0 {
5149:                base.clone()
5150:            } else {
5151:                format!("{base}-g{generation}")
5152:            };
5153:            info!(name, "cleaning up apple container");
5154:            let _ = tokio::process::Command::new("container")
5155:                .args(["stop", &name])
5156:                .output()
5157:                .await;
5158:            let _ = tokio::process::Command::new("container")
5159:                .args(["rm", &name])
5160:                .output()
5161:                .await;
5162:        }
5163:        self.name_generations.write().await.remove(&id.key);
5164:        Ok(())
5165:    }
5166:}
