5184:/// Select the sandbox backend based on config and platform availability.
5185:///
5186:/// When `backend` is `"auto"` (the default):
5187:/// - On macOS, prefer Apple Container if the `container` CLI is installed
5188:///   (each sandbox runs in a lightweight VM — stronger isolation than Docker).
5189:/// - Prefer Podman (daemonless, rootless) over Docker when available.
5190:/// - Fall back to Docker, then restricted-host otherwise.
5191:fn select_backend(config: SandboxConfig) -> Arc<dyn Sandbox> {
5192:    match config.backend.as_str() {
5193:        "docker" => Arc::new(DockerSandbox::new(config)),
5194:        "podman" => Arc::new(DockerSandbox::podman(config)),
5195:        #[cfg(target_os = "macos")]
5196:        "apple-container" => {
5197:            if !ensure_apple_container_service() {
5198:                tracing::warn!(
5199:                    "apple container service could not be started; \
5200:                     run `container system start` manually, then restart moltis"
5201:                );
5202:            }
5203:            let apple_backend: Arc<dyn Sandbox> =
5204:                Arc::new(AppleContainerSandbox::new(config.clone()));
5205:            maybe_wrap_with_failover(apple_backend, &config)
5206:        },
5207:        "restricted-host" => {
5208:            tracing::info!("sandbox backend: restricted-host (env clearing, rlimits)");
5209:            Arc::new(RestrictedHostSandbox::new(config))
5210:        },
5211:        "wasm" | "wasmtime" => create_wasm_backend(config),
5212:        _ => auto_detect_backend(config),
5213:    }
5214:}
