5216:/// Create a WASM sandbox backend, falling back to `RestrictedHostSandbox` if
5217:/// the feature is disabled or initialisation fails.
5218:fn create_wasm_backend(config: SandboxConfig) -> Arc<dyn Sandbox> {
5219:    #[cfg(feature = "wasm")]
5220:    {
5221:        match WasmSandbox::new(config.clone()) {
5222:            Ok(sandbox) => {
5223:                tracing::info!("sandbox backend: wasm (WASI-isolated execution)");
5224:                Arc::new(sandbox)
5225:            },
5226:            Err(e) => {
5227:                tracing::warn!(%e, "failed to initialize wasmtime engine, falling back to restricted-host");
5228:                Arc::new(RestrictedHostSandbox::new(config))
5229:            },
5230:        }
5231:    }
5232:    #[cfg(not(feature = "wasm"))]
5233:    {
5234:        tracing::warn!("wasm sandbox requested but feature not compiled in; using restricted-host");
5235:        Arc::new(RestrictedHostSandbox::new(config))
5236:    }
5237:}
