5239:/// Wrap a primary sandbox backend with a failover chain.
5240:///
5241:/// Tries Podman, then Docker as fallback, then restricted-host, returning the
5242:/// primary unwrapped if no fallback runtime is available.
5243:#[cfg(target_os = "macos")]
5244:fn maybe_wrap_with_failover(primary: Arc<dyn Sandbox>, config: &SandboxConfig) -> Arc<dyn Sandbox> {
5245:    let primary_name = primary.backend_name();
5246:
5247:    // Try Podman as fallback (skip if primary is already Podman).
5248:    if primary_name != "podman" && is_cli_available("podman") {
5249:        tracing::info!(
5250:            primary = primary_name,
5251:            fallback = "podman",
5252:            "sandbox backend failover enabled"
5253:        );
5254:        return Arc::new(FailoverSandbox::new(
5255:            primary,
5256:            Arc::new(DockerSandbox::podman(config.clone())),
5257:        ));
5258:    }
5259:
5260:    // Try Docker as fallback (skip if primary is already Docker).
5261:    if primary_name != "docker"
5262:        && should_use_docker_backend(is_cli_available("docker"), is_docker_daemon_available())
5263:    {
5264:        tracing::info!(
5265:            primary = primary_name,
5266:            fallback = "docker",
5267:            "sandbox backend failover enabled"
5268:        );
5269:        return Arc::new(FailoverSandbox::new(
5270:            primary,
5271:            Arc::new(DockerSandbox::new(config.clone())),
5272:        ));
5273:    }
5274:
5275:    // Use restricted-host as fallback if no OCI runtime is available.
5276:    tracing::info!(
5277:        primary = primary_name,
5278:        fallback = "restricted-host",
5279:        "sandbox backend failover enabled (restricted-host)"
5280:    );
5281:    Arc::new(FailoverSandbox::new(
5282:        primary,
5283:        Arc::new(RestrictedHostSandbox::new(config.clone())),
5284:    ))
5285:}
