5287:/// Check whether an error message indicates a Docker daemon connectivity issue.
5288:fn is_docker_failover_error(message: &str) -> bool {
5289:    let lower = message.to_ascii_lowercase();
5290:    lower.contains("cannot connect to the docker daemon")
5291:        || lower.contains("is the docker daemon running")
5292:        || lower.contains("error during connect")
5293:        || lower.contains("connection refused")
