5307:fn auto_detect_backend(config: SandboxConfig) -> Arc<dyn Sandbox> {
5308:    #[cfg(target_os = "macos")]
5309:    {
5310:        if is_cli_available("container") {
5311:            if ensure_apple_container_service() {
5312:                tracing::info!("sandbox backend: apple-container (VM-isolated, preferred)");
5313:                let apple_backend: Arc<dyn Sandbox> =
5314:                    Arc::new(AppleContainerSandbox::new(config.clone()));
5315:                return maybe_wrap_with_failover(apple_backend, &config);
5316:            }
5317:            tracing::warn!(
5318:                "apple container CLI found but service could not be started; \
5319:                 falling back to podman/docker"
5320:            );
5321:        }
5322:    }
5323:
5324:    // Prefer Podman (daemonless, rootless by default) over Docker.
5325:    if is_cli_available("podman") {
5326:        tracing::info!("sandbox backend: podman (daemonless, preferred over docker)");
5327:        return Arc::new(DockerSandbox::podman(config));
5328:    }
5329:
5330:    if should_use_docker_backend(is_cli_available("docker"), is_docker_daemon_available()) {
5331:        tracing::info!("sandbox backend: docker");
5332:        return Arc::new(DockerSandbox::new(config));
5333:    }
5334:
5335:    if is_cli_available("docker") {
5336:        tracing::warn!(
5337:            "docker CLI detected but daemon is not accessible; \
5338:             falling back to restricted-host sandbox"
5339:        );
5340:    }
5341:
5342:    // Use restricted-host sandbox before falling back to NoSandbox.
5343:    tracing::info!(
5344:        "sandbox backend: restricted-host (env clearing, rlimits; no container runtime available)"
5345:    );
5346:    Arc::new(RestrictedHostSandbox::new(config))
5347:}
