5372:/// Return `true` when the installed Podman version supports `host-gateway`
5373:/// in `--add-host` (added in Podman 5.0).
5374:fn podman_supports_host_gateway() -> bool {
5375:    let Ok(output) = std::process::Command::new("podman")
5376:        .args(["version", "--format", "{{.Client.Version}}"])
5377:        .output()
5378:    else {
5379:        return false;
5380:    };
5381:    let version_str = String::from_utf8_lossy(&output.stdout);
5382:    let major: u32 = version_str
5383:        .trim()
5384:        .split('.')
5385:        .next()
5386:        .and_then(|s| s.parse().ok())
5387:        .unwrap_or(0);
5388:    major >= 5
5389:}
