5391:/// Resolve the host IP that a Podman container (< 5.0) can use to reach the
5392:/// host.  Rootless Podman defaults to slirp4netns where the host is always
5393:/// `10.0.2.2`.  Rootful Podman uses a bridge network whose gateway we query
5394:/// with `podman network inspect`.
5395:fn podman_resolve_host_ip() -> Option<String> {
5396:    let rootless = std::process::Command::new("podman")
5397:        .args(["info", "--format", "{{.Host.Security.Rootless}}"])
5398:        .output()
5399:        .ok()
5400:        .map(|o| String::from_utf8_lossy(&o.stdout).trim().to_string());
5401:
5402:    if rootless.as_deref() == Some("true") {
5403:        // slirp4netns (default rootless network before Podman 5.0) maps the
5404:        // host to 10.0.2.2.
5405:        return Some("10.0.2.2".to_string());
5406:    }
5407:
5408:    // Rootful — ask for the gateway of the default "podman" network.
5409:    let output = std::process::Command::new("podman")
5410:        .args([
5411:            "network",
5412:            "inspect",
5413:            "podman",
5414:            "--format",
5415:            "{{(index .Subnets 0).Gateway}}",
5416:        ])
5417:        .output()
5418:        .ok()?;
5419:    let gateway = String::from_utf8_lossy(&output.stdout).trim().to_string();
5420:    if gateway.is_empty() {
5421:        None
5422:    } else {
5423:        Some(gateway)
5424:    }
5425:}
