5460:/// Routes sandbox decisions per-session, with per-session overrides on top of global config.
5461:pub struct SandboxRouter {
5462:    config: SandboxConfig,
5463:    backend: Arc<dyn Sandbox>,
5464:    /// Per-session overrides: true = sandboxed, false = direct execution.
5465:    overrides: RwLock<HashMap<String, bool>>,
5466:    /// Per-session image overrides.
5467:    image_overrides: RwLock<HashMap<String, String>>,
5468:    /// Runtime override for the global default image (set via API, persisted externally).
5469:    global_image_override: RwLock<Option<String>>,
5470:    /// Event channel for sandbox lifecycle events (prepare/provision/build feedback).
5471:    event_tx: tokio::sync::broadcast::Sender<SandboxEvent>,
5472:    /// Session keys that have already completed sandbox initialization.
5473:    /// Used to avoid repeating first-run preparation banners on every command.
5474:    prepared_sessions: RwLock<HashSet<String>>,
5475:    /// Whether a sandbox image pre-build is currently in progress.
5476:    /// Used by the gateway to show a banner in the UI.
5477:    pub building_flag: std::sync::atomic::AtomicBool,
5478:}
