5480:impl SandboxRouter {
5481:    pub fn new(config: SandboxConfig) -> Self {
5482:        // Always create a real sandbox backend, even when global mode is Off,
5483:        // because per-session overrides can enable sandboxing dynamically.
5484:        let backend = create_sandbox_backend(config.clone());
5485:        let (event_tx, _) = tokio::sync::broadcast::channel(32);
5486:        Self {
5487:            config,
5488:            backend,
5489:            overrides: RwLock::new(HashMap::new()),
5490:            image_overrides: RwLock::new(HashMap::new()),
5491:            global_image_override: RwLock::new(None),
5492:            event_tx,
5493:            prepared_sessions: RwLock::new(HashSet::new()),
5494:            building_flag: std::sync::atomic::AtomicBool::new(false),
5495:        }
5496:    }
