5537:    /// Check whether a session should run sandboxed.
5538:    /// Returns `false` when no real container runtime is available, regardless of
5539:    /// config mode or per-session overrides. Otherwise, per-session override takes
5540:    /// priority, then falls back to global mode.
5541:    pub async fn is_sandboxed(&self, session_key: &str) -> bool {
5542:        if !self.backend.is_real() {
5543:            return false;
5544:        }
5545:        if let Some(&override_val) = self.overrides.read().await.get(session_key) {
5546:            return override_val;
5547:        }
5548:        match self.config.mode {
5549:            SandboxMode::Off => false,
5550:            SandboxMode::All => true,
5551:            SandboxMode::NonMain => session_key != "main",
5552:        }
5553:    }
