5568:    /// Derive a SandboxId for a given session key.
5569:    /// The key is sanitized for use as a container name (only alphanumeric, dash, underscore, dot).
5570:    pub fn sandbox_id_for(&self, session_key: &str) -> SandboxId {
5571:        let sanitized: String = session_key
5572:            .chars()
5573:            .map(|c| {
5574:                if c.is_ascii_alphanumeric() || c == '-' || c == '_' || c == '.' {
5575:                    c
5576:                } else {
5577:                    '-'
5578:                }
5579:            })
5580:            .collect();
5581:        SandboxId {
5582:            scope: self.config.scope.clone(),
5583:            key: sanitized,
5584:        }
5585:    }
