5588:    pub async fn cleanup_session(&self, session_key: &str) -> Result<()> {
5589:        let id = self.sandbox_id_for(session_key);
5590:        self.backend.cleanup(&id).await?;
5591:        self.remove_override(session_key).await;
5592:        self.clear_prepared_session(session_key).await;
5593:        Ok(())
5594:    }
