5629:    /// Set a runtime override for the global default image.
5630:    /// Pass `None` to revert to the config/hardcoded default.
5631:    pub async fn set_global_image(&self, image: Option<String>) {
5632:        *self.global_image_override.write().await = image;
5633:    }
