5635:    /// Get the current effective default image (runtime override > config > hardcoded).
5636:    pub async fn default_image(&self) -> String {
5637:        if let Some(ref img) = *self.global_image_override.read().await {
5638:            return img.clone();
5639:        }
5640:        self.config
5641:            .image
5642:            .clone()
5643:            .unwrap_or_else(|| DEFAULT_SANDBOX_IMAGE.to_string())
5644:    }
5645:
5646:    /// Resolve the container image for a session.
5647:    ///
5648:    /// Priority (highest to lowest):
5649:    /// 1. `skill_image` — from a skill's Dockerfile cache
5650:    /// 2. Per-session override (`session.sandbox_image`)
5651:    /// 3. Runtime global override (`set_global_image`)
5652:    /// 4. Global config (`config.tools.exec.sandbox.image`)
5653:    /// 5. Default constant (`DEFAULT_SANDBOX_IMAGE`)
5654:    pub async fn resolve_image(&self, session_key: &str, skill_image: Option<&str>) -> String {
5655:        if let Some(img) = skill_image {
5656:            return img.to_string();
5657:        }
5658:        if let Some(img) = self.image_overrides.read().await.get(session_key) {
5659:            return img.clone();
5660:        }
5661:        self.default_image().await
5662:    }
5663:}
