5849:    impl TestSandbox {
5850:        fn new(
5851:            name: &'static str,
5852:            ensure_ready_error: Option<&str>,
5853:            exec_error: Option<&str>,
5854:        ) -> Self {
5855:            Self {
5856:                name,
5857:                ensure_ready_error: ensure_ready_error.map(ToOwned::to_owned),
5858:                exec_error: exec_error.map(ToOwned::to_owned),
5859:                ensure_ready_calls: AtomicUsize::new(0),
5860:                exec_calls: AtomicUsize::new(0),
5861:                cleanup_calls: AtomicUsize::new(0),
5862:            }
5863:        }
