5882:    #[async_trait::async_trait]
5883:    impl Sandbox for TestSandbox {
5884:        fn backend_name(&self) -> &'static str {
5885:            self.name
5886:        }
5887:
5888:        async fn ensure_ready(&self, _id: &SandboxId, _image_override: Option<&str>) -> Result<()> {
5889:            self.ensure_ready_calls.fetch_add(1, Ordering::SeqCst);
5890:            if let Some(ref msg) = self.ensure_ready_error {
5891:                return Err(Error::message(msg));
5892:            }
5893:            Ok(())
5894:        }
5895:
5896:        async fn exec(
5897:            &self,
5898:            _id: &SandboxId,
5899:            _command: &str,
5900:            _opts: &ExecOpts,
5901:        ) -> Result<ExecResult> {
5902:            self.exec_calls.fetch_add(1, Ordering::SeqCst);
5903:            if let Some(ref msg) = self.exec_error {
5904:                return Err(Error::message(msg));
5905:            }
5906:            Ok(ExecResult {
5907:                stdout: "ok".into(),
5908:                stderr: String::new(),
5909:                exit_code: 0,
5910:            })
5911:        }
5912:
5913:        async fn cleanup(&self, _id: &SandboxId) -> Result<()> {
5914:            self.cleanup_calls.fetch_add(1, Ordering::SeqCst);
5915:            Ok(())
5916:        }
5917:    }
